import{_ as e,o as t,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"FAQ & 故障排除","description":"","frontmatter":{},"headers":[],"relativePath":"zh/faq.md","filePath":"zh/faq.md"}'),i={name:"zh/faq.md"};function l(c,a,r,d,n,m){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="faq-故障排除" tabindex="-1"><i class="ph ph-question"></i> FAQ &amp; 故障排除 <a class="header-anchor" href="#faq-故障排除" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ &amp; 故障排除&quot;">​</a></h1><p>本节汇编了在 WebGL 优化期间遇到的最常见问题的答案和典型问题的解决方案。</p><h2 id="安装和演示场景" tabindex="-1"><i class="ph ph-package"></i> 安装和演示场景 <a class="header-anchor" href="#安装和演示场景" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; 安装和演示场景&quot;">​</a></h2><details class="details custom-block"><summary>问：我打开了演示场景，但所有材质和对象都是粉红色的！</summary><p><strong>答：</strong> 您的项目利用了 URP，而演示场景默认配置为 BiRP。只需解压缩位于 <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code> 的包即可。着色器将自动更新。</p></details><details class="details custom-block"><summary>问：我安装了插件，但在视觉上，游戏绝对没有改变任何内容。</summary><p><strong>答：</strong> 查看此检查清单：</p><ul><li>插件是否在 Project Settings 中启用？缩放器是否已添加且处于活动状态？</li><li>Unity 图形最初是否设置为最大值？如果设置已经很低，插件就没有什么可降低的了。</li><li>也许设备毫不费力地处理了负载，而且 FPS 是稳定的。将 <code>Dashboard</code> 预制件添加到场景中，以观察索引器当前的决策。</li><li>如果所有配置均正确但没有效果 — 请联系我们，我们将协助您进行故障排除。</li></ul></details><h2 id="分辨率和用户界面-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> 分辨率和用户界面 (UI) <a class="header-anchor" href="#分辨率和用户界面-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; 分辨率和用户界面 (UI)&quot;">​</a></h2><details class="details custom-block"><summary>问：分辨率没有改变（Resolution Scaler 处于非活动状态）。</summary><p><strong>答：</strong> 两个最常见的原因：</p><ol><li>如果您使用的是 <strong>BiRP</strong> 以及 <code>RenderTextureScaling</code> 模式：检查缩放器设置中的 <code>Target Tags</code> 数组。如果您的游戏相机具有不同的名称（不是 <code>MainCamera</code>），则必须输入其标签。否则，插件将根本无法找到它。</li><li><code>NativeBrowserScaling</code> 模式专用于构建完成的 WebGL 版本。它在 Unity 编辑器中不执行任何操作。</li></ol></details><details class="details custom-block"><summary>问：当 FPS 下降时，我的 UI 也变得模糊！</summary><p><strong>答：</strong> 确认在 BiRP 中，您选择了 <code>RenderTextureScaling</code>。Canvas 本身必须设置为 <code>Screen Space - Overlay</code> 模式（或使用专用的 UI 相机）。</p></details><details class="details custom-block"><summary>问：标准 UI 按钮按下正常，但我对 3D 对象的自定义鼠标点击偏移了。</summary><p><strong>答：</strong> 标准 EventSystem 事件由我们的 <code>WebScaledPhysicsRaycaster</code> 组件自动修复。但是，如果您通过代码执行自定义射线投射（<code>Camera.ScreenPointToRay()</code>），它将由于纹理大小更改而错过目标。请利用插件的专用方法：<code>WebRaycasterUtility.TryComputeScaledRay()</code>。</p></details><h2 id="指标和系统行为" tabindex="-1"><i class="ph ph-chart-line-up"></i> 指标和系统行为 <a class="header-anchor" href="#指标和系统行为" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; 指标和系统行为&quot;">​</a></h2><details class="details custom-block"><summary>问：由于延迟，图形质量降低。目前，FPS 再次变高，但图形并没有改善！</summary><p><strong>答：</strong> 可能是触发了 <strong>Anti Yo-Yo 惩罚系统</strong>。插件暂时阻止了升级以防止质量闪烁 (Quality flickering)。</p><ul><li>如果您希望图形恢复得更快，请减小 <code>Penalty Lockout Duration</code> 参数（例如，减小到 10 秒）。</li><li>另外，检查 <code>Increase Cooldown</code> 参数 — 等待时间可能设置得太高了。</li></ul></details><details class="details custom-block"><summary>问：仪表板不断显示 CPU 瓶颈或 Unknown，即使场景是空的。</summary><p><strong>答：</strong> 确保在 Player Settings 中启用了 <code>Frame Timing Stats</code>。此外，验证 <code>Application.targetFrameRate = -1</code>。移除硬性帧限制可将指标从浏览器内人为的 <code>setTimeout</code> 延迟中解放出来。</p></details><details class="details custom-block"><summary>问：角色或物理对象在严重延迟期间开始出现卡顿。</summary><p><strong>答：</strong> 这是 <code>Physics Step Scaler</code> 的副作用。它修改了 <code>Time.fixedDeltaTime</code> 以拯救处理器免受过载。为确保运动视觉上保持流畅，请在角色的 <code>Rigidbody</code> 组件上启用 <code>Interpolate</code> 模式。</p></details><details class="details custom-block"><summary>问：启用了阴影缩放器，但性能并未提高，且阴影仍然存在。</summary><p><strong>答：</strong> 插件专门管理动态（实时）阴影。如果您场景中的照明是烘焙的 (Baked/Lightmaps)，则缩放器将对其完全没有影响。</p></details><h2 id="自定义缩放器" tabindex="-1"><i class="ph ph-code"></i> 自定义缩放器 <a class="header-anchor" href="#自定义缩放器" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; 自定义缩放器&quot;">​</a></h2><details class="details custom-block"><summary>问：我的自定义缩放器在编辑器中运行完美，但在 WebGL 构建中却消失得无影无踪！</summary><p><strong>答：</strong> IL2CPP 编译器在构建过程中将其作为“死代码”剥离。请始终在您的自定义缩放器类上方应用 <code>[UnityEngine.Scripting.Preserve]</code> 属性。</p></details>',16)])])}const h=e(i,[["render",l]]);export{p as __pageData,h as default};
